1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (count: number, isLive: boolean): boolean =>
15	  count === 3 || (count === 2 && isLive);
16	
17	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
18	  const liveKeys = new Set(liveCells.map(cellKey));
19	  const candidates = new Map<string, Cell>();
20	  const neighborCounts = new Map<string, number>();
21	
22	  for (const cell of liveCells) {
23	    for (const neighbor of neighborsOf(cell)) {
24	      const k = cellKey(neighbor);
25	      candidates.set(k, neighbor);
26	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
27	    }
28	  }
29	
30	  const nextCells: Cell[] = [];
31	  for (const [k, cell] of candidates) {
32	    if (survives(neighborCounts.get(k) ?? 0, liveKeys.has(k))) {
33	      nextCells.push(cell);
34	    }
35	  }
36	  return nextCells;
37	};
