1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	const sortCells = (cells: [number, number][]): [number, number][] =>
5	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
6	
7	describe("Game of Life - nextGeneration", () => {
8	  it("empty grid stays empty", () => {
9	    expect(nextGeneration([])).toEqual([]);
10	  });
11	  it("single live cell dies (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	  it("two adjacent live cells both die (underpopulation)", () => {
15	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
16	  });
17	  it("block (2x2) is a still life - unchanged", () => {
18	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
20	  });
21	  it("blinker oscillates from vertical to horizontal", () => {
22	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
23	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
24	    expect(sortCells(nextGeneration(vertical))).toEqual(sortCells(horizontal));
25	  });
26	  it("dead cell with exactly 3 neighbors becomes alive (reproduction)", () => {
27	    // L-shape: ##/#. - dead cell (1,1) has 3 live neighbors → becomes alive
28	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
29	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
30	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
31	  });
32	  it("live cell with 4 neighbors dies (overpopulation)", () => {
33	    // X pattern: center (1,1) is live with 4 diagonal neighbors → dies
34	    //   #.#
35	    //   .#.
36	    //   #.#
37	    const input: [number, number][] = [
38	      [0, 0], [2, 0],
39	      [1, 1],
40	      [0, 2], [2, 2],
41	    ];
42	    const result = nextGeneration(input);
43	    const resultSet = new Set(result.map(([x, y]) => `${x},${y}`));
44	    expect(resultSet.has("1,1")).toBe(false);
45	  });
46	  it("handles negative coordinates", () => {
47	    // Block at negative coordinates - should remain unchanged
48	    const block: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
49	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
50	  });
51	});
